+const GZIP_MAGIC: [2]u8 = .{ 0x1f, 0x8b };
+const DEFLATE_CM: u8 = 8;
+const FTEXT: u8 = 1;
+const FHCRC: u8 = 2;
+const FEXTRA: u8 = 4;
+const FNAME: u8 = 8;
+const FCOMMENT: u8 = 16;
